import React from "react";

export default function ColorDisplay({ color, previousColor }) {
  return (
    <div
      className="color-display"
      style={{
        display: "flex", // Use flexbox to split the display
        width: "654px",
        height: "300px",
        border: "1px solid #000",
      }}
    >
      {/* Left section for the previous color */}
      <div
        className="color-display-left"
        style={{
          background: previousColor,
          flex: 1, // Take up half the space
        }}
      ></div>

      {/* Right section for the current color */}
      <div
        className="color-display-right"
        style={{
          background: color,
          flex: 1, // Take up half the space
        }}
      ></div>
    </div>
  );
}
